-- unaccent normalizes diacritics so "rodriguez" matches "Rodríguez" in the player search query.
CREATE EXTENSION IF NOT EXISTS unaccent;

CREATE TABLE IF NOT EXISTS players (
  id             BIGINT      PRIMARY KEY,
  team_fifa_code VARCHAR(8)  NOT NULL REFERENCES teams(fifa_code) ON DELETE CASCADE,
  name           TEXT        NOT NULL,
  first_name     TEXT,
  last_name      TEXT,
  age            SMALLINT,
  nationality    TEXT,
  position       VARCHAR(16) NOT NULL CHECK (
    position IN ('goalkeeper', 'defender', 'midfielder', 'attacker')
  ),
  photo_url      TEXT,
  club_name      TEXT,
  club_logo_url  TEXT
);

CREATE INDEX IF NOT EXISTS idx_players_team_fifa_code ON players(team_fifa_code);
CREATE INDEX IF NOT EXISTS idx_players_position       ON players(position);

